import numpy as np
from scipy.linalg import expm
from typing import List, Tuple

def commutator(A: np.ndarray, B: np.ndarray) -> np.ndarray:
    return A @ B - B @ A

def first_order_error_bound(H_terms: List[np.ndarray], t: float, r: int) -> float:
    L = len(H_terms)
    total = 0.0

    for j in range(L):
        for k in range(j + 1, L):
            comm_norm = np.linalg.norm(commutator(H_terms[j], H_terms[k]), ord=2)
            total += comm_norm

    return total * t**2 / (2 * r)

def second_order_error_bound(H_terms: List[np.ndarray], t: float, r: int) -> float:
    L = len(H_terms)
    total = 0.0

    for j in range(L):
        for k in range(L):
            for l in range(L):
                if j != k:
                    comm_jk = commutator(H_terms[j], H_terms[k])
                    nested = commutator(comm_jk, H_terms[l])
                    total += np.linalg.norm(nested, ord=2)

    return total * t**3 / (12 * r**2)

def first_order_trotter(H_terms, t, r):
    dt = t / r
    dim = H_terms[0].shape[0]
    U_step = np.eye(dim, dtype=complex)
    for H_j in H_terms:
        U_step = expm(-1j * H_j * dt) @ U_step
    return np.linalg.matrix_power(U_step, r)

def analyze_bound_tightness(H_terms: List[np.ndarray], t: float, 
                             steps: List[int]) -> Tuple[List[float], List[float], List[float]]:
    H_total = sum(H_terms)
    U_exact = expm(-1j * H_total * t)

    actual = []
    bounds_1st = []
    bounds_2nd = []

    for r in steps:
        U_trotter = first_order_trotter(H_terms, t, r)
        actual.append(np.linalg.norm(U_trotter - U_exact, ord=2))
        bounds_1st.append(first_order_error_bound(H_terms, t, r))
        bounds_2nd.append(second_order_error_bound(H_terms, t, r))

    return actual, bounds_1st, bounds_2nd

def tensor(ops):
    result = ops[0]
    for op in ops[1:]:
        result = np.kron(result, op)
    return result

I = np.eye(2, dtype=complex)
X = np.array([[0, 1], [1, 0]], dtype=complex)
Z = np.array([[1, 0], [0, -1]], dtype=complex)

H_terms = [
    tensor([Z, Z]),
    0.5 * tensor([X, I]),
    0.5 * tensor([I, X])
]

steps = [4, 8, 16, 32, 64]
t = 1.0

actual, bound1, bound2 = analyze_bound_tightness(H_terms, t, steps)

print("Error Bound Analysis:")
print(f"{'Steps':>6} {'Actual':>12} {'1st Bound':>12} {'Ratio':>8}")
print("-" * 42)
for i, r in enumerate(steps):
    ratio = bound1[i] / actual[i] if actual[i] > 1e-14 else float('inf')
    print(f"{r:6d} {actual[i]:12.2e} {bound1[i]:12.2e} {ratio:8.2f}")
